    <div class="tab tab-infrastructure" data-tab="switches" data-testid="tab-switches" title="Federation execution configuration switches">Switches</div>
    <div class="tab tab-infrastructure" data-tab="tags" data-testid="tab-tags" title="User-defined tags for RTI callbacks">Tags</div>
    <div class="tab tab-infrastructure" data-tab="time" data-testid="tab-time" title="Time stamp and lookahead configuration">Time</div>
    <div class="tab-section-header">Documentation</div>
    <div class="tab tab-documentation" data-tab="notes" data-testid="tab-notes" title="Notes and documentation from FOM modules">Notes</div>
    <div class="tab tab-issues" data-tab="issues" data-testid="tab-issues" title="Validation issues, conflicts, and errors" style="display:none">Issues</div>
